-- STEP 1: query [kommuner]
SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Stavanger%' LIMIT 1;

-- STEP BOUNDARY --

